__kernel void hotspotOpt1(
    __global const float* power,
    __global const float* tempIn,
    __global float* tempOut,
    float stepDivCap,
    int numCols,
    int numRows,
    int layers,
    float ce,
    float cw,
    float cn,
    float cs,
    float ct,
    float cb,
    float cc)
{
    int x = get_global_id(0);
    int y = get_global_id(1);

    if (x >= numCols || y >= numRows)
        return;

    for (int z = 0; z < layers; z++) {
        int c = x + y * numCols + z * numCols * numRows;

        int w = (0 == x) ? c : c - 1;
        int e = (numCols - 1 == x) ? c : c + 1;
        int n = (0 == y) ? c : c - numCols;
        int s = (numRows - 1 == y) ? c : c + numCols;
        int b = (0 == z) ? c : c - numCols * numRows;
        int t = (layers - 1 == z) ? c : c + numCols * numRows;

        tempOut[c] = cc * tempIn[c] + cw * tempIn[w] + ce * tempIn[e]
            + cs * tempIn[s] + cn * tempIn[n] + cb * tempIn[b] + ct * tempIn[t]
            + stepDivCap * power[c] + ct * 80.0f;
    }
}
